/**
 * Real customer-grade samples generated by The Vantage.
 * Used across landing pages, sliders, and case studies as proof-of-quality.
 *
 * Files live in /public/vantage/ — the paths below are URL-relative.
 * No imports; just paths the browser can fetch.
 */

export interface VantageSample {
  id: string;
  category: "construction" | "cleanup" | "setup" | "listing_single" | "listing_bundle" | "sketch_to_real";
  label: string;
  byline: string;
  /** Final delivered video — what you put on Reels */
  video: string;
  /** AI-reconstructed "before" state (only for transformations) */
  before?: string;
  /** Original "after" photo the customer uploaded */
  after?: string;
  /** Optional poster frame for video <video poster> */
  poster?: string;
}

