/**
 * The 6-photo Listing Bundle sample. Each entry is one source photo + its
 * 5-second cinematic clip. Wire these into a slider to demo the bundle flow.
 */
export const VANTAGE_LISTING_BUNDLE = Array.from({ length: 6 }, (_, i) => ({
  index: i + 1,
  photo: `/vantage/listing-bundle/${i + 1}.webp`,
  clip: `/vantage/listing-bundle/${i + 1}.mp4`,
}));

/** Quick-access lookups */
export const getSampleById = (id: string) => VANTAGE_SAMPLES.find((s) => s.id === id);
export const getSamplesByCategory = (category: VantageSample["category"]) =>
  VANTAGE_SAMPLES.filter((s) => s.category === category);

/** Top three for homepage hero / featured slots */
export const FEATURED_SAMPLES = [
  VANTAGE_SAMPLES.find((s) => s.id === "ranch-build")!,
  VANTAGE_SAMPLES.find((s) => s.id === "backyard-slow-reveal")!,
  VANTAGE_SAMPLES.find((s) => s.id === "ranch-clean")!,
];
